import React, { useState } from 'react';
import Sidebar from '../components/Sidebar';
import { useTheme } from '../context/ThemeContext';
import ConfiguracaoService from '../services/configuracaoService';
import './Configuracoes.css';

const Configuracoes = () => {
  const { theme, toggleTheme, loading: loadingTheme } = useTheme();
  const [carregando, setCarregando] = useState(false);
  const [mensagem, setMensagem] = useState('');

  const handleThemeChange = async (novoTema) => {
    setCarregando(true);
    setMensagem('');

    try {
      await ConfiguracaoService.salvarTema(novoTema);
      // Forçar atualização do contexto
      window.location.reload();
    } catch (error) {
      console.error('Erro ao salvar tema:', error);
      setMensagem('Erro ao salvar tema. Tente novamente.');
    } finally {
      setCarregando(false);
    }
  };

  const limparDados = async () => {
    if (!window.confirm('Tem certeza que deseja limpar todos os dados? Esta ação não pode ser desfeita.')) {
      return;
    }

    setCarregando(true);
    setMensagem('');

    try {
      await ConfiguracaoService.limparConfiguracoes();
      setMensagem('Dados limpos com sucesso!');
      setTimeout(() => {
        window.location.reload();
      }, 2000);
    } catch (error) {
      console.error('Erro ao limpar dados:', error);
      setMensagem('Erro ao limpar dados. Tente novamente.');
    } finally {
      setCarregando(false);
    }
  };

  if (loadingTheme) {
    return (
      <div>
        <Sidebar />
        <div className="config-container">
          <div className="loading">
            <p>Carregando configurações...</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div>
      <Sidebar />
      <div className="config-container">
        <div className="config-header">
          <h1>Configurações</h1>
          <p>Personalize sua experiência</p>
        </div>

        {mensagem && (
          <div className={`mensagem ${mensagem.includes('sucesso') || mensagem.includes('limpos') ? 'sucesso' : 'erro'}`}>
            {mensagem}
          </div>
        )}

        <div className="config-section">
          <h2>Aparência</h2>
          <p>Escolha o tema visual da aplicação</p>

          <div className="theme-selector">
            <div className="theme-option">
              <input
                type="radio"
                id="dark-theme"
                name="theme"
                value="dark"
                checked={theme === 'dark'}
                onChange={() => handleThemeChange('dark')}
                disabled={carregando}
              />
              <div className="theme-card">
                <div className="theme-preview dark">
                  <div className="preview-header"></div>
                  <div className="preview-content"></div>
                </div>
                <div className="theme-name">Dark Mode</div>
                <div className="theme-description">Tema escuro para melhor conforto visual</div>
              </div>
            </div>

            <div className="theme-option">
              <input
                type="radio"
                id="light-theme"
                name="theme"
                value="light"
                checked={theme === 'light'}
                onChange={() => handleThemeChange('light')}
                disabled={carregando}
              />
              <div className="theme-card">
                <div className="theme-preview light">
                  <div className="preview-header"></div>
                  <div className="preview-content"></div>
                </div>
                <div className="theme-name">Light Mode</div>
                <div className="theme-description">Tema claro para ambientes bem iluminados</div>
              </div>
            </div>
          </div>
        </div>

        <div className="config-section">
          <h2>Sobre a Aplicação</h2>
          <p>Informações sobre o sistema</p>

          <div className="app-info">
            <div className="info-item">
              <strong>Versão:</strong> 1.0.0
            </div>
            <div className="info-item">
              <strong>Banco de Dados:</strong> IndexedDB (Dexie)
            </div>
            <div className="info-item">
              <strong>Tecnologias:</strong> React, CSS3, IndexedDB
            </div>
            <div className="info-item">
              <strong>Armazenamento:</strong> Local no navegador
            </div>
          </div>
        </div>

        <div className="config-section">
          <h2>Atalhos</h2>
          <p>Comandos rápidos para melhor produtividade</p>

          <div className="shortcuts">
            <div className="shortcut-item">
              <kbd>N</kbd>
              <span>Navegar para catálogo</span>
            </div>
            <div className="shortcut-item">
              <kbd>G</kbd>
              <span>Gerenciar produtos</span>
            </div>
            <div className="shortcut-item">
              <kbd>C</kbd>
              <span>Configurações</span>
            </div>
            <div className="shortcut-item">
              <kbd>ESC</kbd>
              <span>Fechar modal</span>
            </div>
          </div>
        </div>

        <div className="config-section">
          <h2>Gerenciamento de Dados</h2>
          <p>Opções para gerenciar seus dados</p>

          <div className="data-actions">
            <button 
              className="btn-danger"
              onClick={limparDados}
              disabled={carregando}
            >
              🗑️ Limpar Todos os Dados
            </button>
            <p className="warning">
              ⚠️ Esta ação irá excluir todos os produtos e configurações salvas.
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Configuracoes;
